import{_ as t,c as a,a3 as o,o as i}from"./chunks/framework.TFRZ2p9Y.js";const l="/jam-starter-package/Images/pingpong_example.gif",r="/jam-starter-package/Images/simple-spin_example.gif",s="/jam-starter-package/Images/texture_scroller.png",n="/jam-starter-package/Images/texture-scroller_example3.gif",m="/jam-starter-package/Images/transform_animator.png",c="/jam-starter-package/Images/transform-animator_example3.gif",w=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Utilities/utilities-animators.md","filePath":"Utilities/utilities-animators.md"}'),p={name:"Utilities/utilities-animators.md"};function d(h,e,u,g,f,b){return i(),a("div",null,e[0]||(e[0]=[o('<h2 id="animators" tabindex="-1">Animators <a class="header-anchor" href="#animators" aria-label="Permalink to &quot;Animators&quot;">​</a></h2><h3 id="ping-pong" tabindex="-1">Ping Pong <a class="header-anchor" href="#ping-pong" aria-label="Permalink to &quot;Ping Pong&quot;">​</a></h3><blockquote><p><em><strong>NOTE</strong> <code>Rotation</code> &amp; <code>Position</code> target World Space</em></p></blockquote><p><img src="'+l+'" alt="example"></p><p>This animator will Ping-Pong the follow transform values if enabled:</p><ul><li>Position</li><li>Rotation</li><li>Scale</li></ul><p>Set the speed <em>( &gt; 0)</em> &amp; the animator curve. This will target the Transform that it&#39;s attached to and will run automatically.</p><h3 id="simple-spin" tabindex="-1">Simple Spin <a class="header-anchor" href="#simple-spin" aria-label="Permalink to &quot;Simple Spin&quot;">​</a></h3><p>This animator will rotate the specified degrees per frame * <code>Time.deltaTime</code>. It targets the attached Transforms world rotation value. Works for both 2D &amp; 3D.</p><p><img src="'+r+'" alt="example"></p><h3 id="texture-scroller" tabindex="-1">Texture Scroller <a class="header-anchor" href="#texture-scroller" aria-label="Permalink to &quot;Texture Scroller&quot;">​</a></h3><p>The texture scroller animator allows you to target multiple renderers to apply UV offsets over time. You select the speed on the X &amp; Y axis.</p><p><img src="'+s+'" alt="test"></p><ul><li><code>RandomOffset</code>: If you want to have a texture be offset between 0.0 -&gt; 1.0 enable this <ul><li>This will be applied only if a speed on either the X or Y axis <code>!= 0.0</code></li></ul></li><li><code>CreateMaterialInstance</code>: If you enable this, a new instance of the target renderer material will be created to prevent global setting of the offsets,</li></ul><p><img src="'+n+'" alt="example"></p><h3 id="transform-animator" tabindex="-1">Transform Animator <a class="header-anchor" href="#transform-animator" aria-label="Permalink to &quot;Transform Animator&quot;">​</a></h3><p>This animator will provide a shake/wobble effect, generally good if you want something to react to being interacted with. It will animate for a random amount of time, limited by specified time range. This does not run automatically, and will need to be called from scripts to trigger. This will target the Transform it&#39;s attached to. See below for the functions that can be called.</p><p><img src="'+m+'" alt="properties"></p><ul><li><code>Time Range</code>: The animator will choose a value between these min &amp; max for how long to animate for</li><li><code>ScaleCurve</code>: This is the value to <strong>multiply the scale by</strong>, so ensure that the value matches expectations!!</li><li><code>Rotation Curve</code>: How the localRotation is applied. <code>transform.localRotation = Quaternion.Lerp(CCW, CW, scaleCurve.Evaluate(dt) - 0.5f);</code></li></ul><p><img src="'+c+'" alt="example"></p><ul><li><code>void Play()</code>: This will cause the animation t play a single time. If its already playing, it will call <code>Stop()</code> before it starts again.</li><li><code>void Loop()</code>: Operates similar to <code>Play()</code>, but will continue until <code>Stop()</code> is called.</li><li><code>void Stop()</code>: Resets the Transform to its original Scale &amp; Rotation</li></ul>',21)]))}const _=t(p,[["render",d]]);export{w as __pageData,_ as default};
